+                    break;
+                case ::rosidl_typesupport_introspection_cpp::ROS_TYPE_INT64:
+                    ser << *(int64_t*)field;
+                    break;
+                case ::rosidl_typesupport_introspection_cpp::ROS_TYPE_UINT64:
+                    ser << *(uint64_t*)field;
+                    break;
+                case ::rosidl_typesupport_introspection_cpp::ROS_TYPE_STRING:
+                    ser << *(std::string*)field;
+                    break;
